We will discuss two primary approaches to solve this problem:

**Idea:**


Factorize the given number XXX by checking divisibility for 2 and then odd numbers up to X\sqrt{X}X​.
For each prime factor that divides XXX, include it (only once) by multiplying it into the answer.
If at the end there remains a prime factor greater than X\sqrt{X}X​, include it as well.
**Explanation:**

Since multiplication allows us to “adjust” the exponents, every prime factor’s influence can be minimized to a single occurrence. By performing trial division, we obtain the product of all distinct primes that divide XXX, which is our answer.

**Code Implementation:**

Below are the C++ and Python implementations for this approach.

C++ Code for Approach 1:`#include &lt;iostream&gt;
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int T;
    cin &gt;&gt; T;
    while(T--){
        long long X;
        cin &gt;&gt; X;
        if(X == 1){
            cout &lt;&lt; 1 &lt;&lt; "\n";
            continue;
        }
        long long ans = 1;
        // Factorize by checking 2 separately
        if(X % 2 == 0){
            ans *= 2;
            while(X % 2 == 0)
                X /= 2;
        }
        // Factorize odd numbers
        for(long long i = 3; i * i &lt;= X; i += 2){
            if(X % i == 0){
                ans *= i;
                while(X % i == 0)
                    X /= i;
            }
        }
        if(X &gt; 1)
            ans *= X;
        cout &lt;&lt; ans &lt;&lt; "\n";
    }
    return 0;
}
`Python Code for Approach 1:`import sys

def min_value(X):
    if X == 1:
        return 1
    ans = 1
    # Factorize 2
    if X % 2 == 0:
        ans *= 2
        while X % 2 == 0:
            X //= 2
    # Factorize odd primes
    i = 3
    while i * i &lt;= X:
        if X % i == 0:
            ans *= i
            while X % i == 0:
                X //= i
        i += 2
    if X &gt; 1:
        ans *= X
    return ans

def main():
    data = sys.stdin.read().strip().split()
    t = int(data[0])
    index = 1
    results = []
    for _ in range(t):
        X = int(data[index])
        index += 1
        results.append(str(min_value(X)))
    sys.stdout.write("\n".join(results))

if __name__ == "__main__":
    main()
`**Idea:**


Precompute all prime numbers up to 109≈31623\sqrt{10^9} \approx 31623109​≈31623 using the Sieve of Eratosthenes.
For each test case, use this list of primes to factorize XXX quickly.
Multiply each distinct prime factor into the answer.
**Explanation:**

This approach is beneficial if there are many test cases since the precomputed list of primes can be reused. The factorization then simply iterates over the primes to extract the distinct factors, achieving the same goal as Approach 1.

**Code Implementation:**

Below are the C++ and Python implementations for the Sieve-based method.

C++ Code for Approach 2:`#include &lt;iostream&gt;
#include &lt;vector&gt;
using namespace std;

// Sieve of Eratosthenes to generate primes up to n
vector&lt;int&gt; sieve(int n) {
    vector&lt;bool&gt; isPrime(n+1, true);
    vector&lt;int&gt; primes;
    isPrime[0] = isPrime[1] = false;
    for (int i = 2; i &lt;= n; i++){
        if(isPrime[i]){
            primes.push_back(i);
            for (long long j = (long long)i*i; j &lt;= n; j += i)
                isPrime[j] = false;
        }
    }
    return primes;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int T;
    cin &gt;&gt; T;
    const int MAX = 31623; // since sqrt(1e9) is approximately 31622
    vector&lt;int&gt; primes = sieve(MAX);

    while(T--){
        long long X;
        cin &gt;&gt; X;
        if(X == 1){
            cout &lt;&lt; 1 &lt;&lt; "\n";
            continue;
        }
        long long ans = 1;
        for(auto p : primes){
            if((long long)p * p &gt; X)
                break;
            if(X % p == 0){
                ans *= p;
                while(X % p == 0)
                    X /= p;
            }
        }
        if(X &gt; 1)
            ans *= X;
        cout &lt;&lt; ans &lt;&lt; "\n";
    }
    return 0;
}
`Python Code for Approach 2:`import sys

def sieve(n):
    is_prime = [True] * (n+1)
    is_prime[0] = is_prime[1] = False
    for i in range(2, int(n**0.5)+1):
        if is_prime[i]:
            for j in range(i*i, n+1, i):
                is_prime[j] = False
    return [i for i, prime in enumerate(is_prime) if prime]

def min_value_with_primes(X, primes):
    if X == 1:
        return 1
    ans = 1
    for p in primes:
        if p * p &gt; X:
            break
        if X % p == 0:
            ans *= p
            while X % p == 0:
                X //= p
    if X &gt; 1:
        ans *= X
    return ans

def main():
    data = sys.stdin.read().strip().split()
    t = int(data[0])
    primes = sieve(31623)
    results = []
    index = 1
    for _ in range(t):
        X = int(data[index])
        index += 1
        results.append(str(min_value_with_primes(X, primes)))
    sys.stdout.write("\n".join(results))

if __name__ == "__main__":
    main()
